// System prompt — governs ALL LLM responses
const SAHAYAK_SYSTEM_PROMPT = `You are SAHAYAK-AI, an agentic decision-support assistant for Indian government Section Officers.

CRITICAL RULES — follow these without exception:
1. Every response must end with: "[OFFICER APPROVAL REQUIRED BEFORE ANY ACTION]"
2. Never claim to have executed any action — you only RECOMMEND.
3. Always cite the relevant Act, Rule, or SOP when giving legal/procedural advice.
4. For RTI matters, always reference the RTI Act, 2005 and the 30-day statutory deadline.
5. For leave matters, reference CCS (Leave) Rules, 1972.
6. For tour/TA-DA, reference SR (Supplementary Rules).
7. Use formal government language — address the officer as "Sir/Ma'am".
8. Format responses clearly using markdown — use **bold** for critical items.
9. Always flag risks, SLA breaches, and policy violations explicitly.
10. Keep responses concise but complete — under 400 words unless a full draft is needed.

Context: You have access to iHRMS data (leave, tour, payroll, employee records), RTI tracking system, grievance portal (CPGRAMS), and file management system via MCP tools.`;

// Call Ollama API with streaming
const callOllama = async (userPrompt, history, onChunk) => {
  // Build message history for context
  const messages = [
    { role: "system", content: SAHAYAK_SYSTEM_PROMPT },
    ...history.slice(-6).map(m => ({          // last 3 exchanges for context
      role:    m.role === "user" ? "user" : "assistant",
      content: m.text,
    })),
    { role: "user", content: userPrompt },
  ];

  const response = await fetch(OLLAMA_URL, {
    method:  "POST",
    headers: { "Content-Type": "application/json" },
    body:    JSON.stringify({
      model:    OLLAMA_MODEL,
      messages,
      stream:   true,
      options: {
        temperature:    0.2,   // low = more consistent, formal government tone
        num_predict:    600,   // max tokens per response
        top_p:          0.9,
        repeat_penalty: 1.1,
      },
    }),
  });

  if (!response.ok) {
    throw new Error(`Ollama error: ${response.status} — is Ollama running? Try: ollama serve`);
  }

  // Stream response chunks
  const reader  = response.body.getReader();
  const decoder = new TextDecoder();
  let   full    = "";

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    const lines = decoder.decode(value).split("\n").filter(Boolean);
    for (const line of lines) {
      try {
        const json  = JSON.parse(line);
        const chunk = json?.message?.content || "";
        if (chunk) {
          full += chunk;
          onChunk(full);   // update UI token by token
        }
        if (json.done) return full;
      } catch (_) { /* incomplete JSON chunk — skip */ }
    }
  }
  return full;
};

