  const t = text.toLowerCase();
  if (t.includes("draft reply") || t.includes("draft note") || t.includes("draft letter"))
    return { type:"approve_draft",  label:"Approve this draft",       rejectLabel:"Reject & redraft" };
  if (t.includes("approve") && (t.includes("leave") || t.includes("application")))
    return { type:"bulk_action",    label:"Approve application(s)",   rejectLabel:"Hold for review" };
  if (t.includes("escalat") || t.includes("reminder"))
    return { type:"approve_draft",  label:"Send escalation/reminder", rejectLabel:"Dismiss" };
  if (t.includes("circulate") || t.includes("send to"))
    return { type:"approve_draft",  label:"Approve & circulate",      rejectLabel:"Save draft only" };
  return { type:"acknowledge", label:"Understood — noted", rejectLabel:null };
};


